import { Suspense } from 'react';
import { FolderOpen, Plus, TrendingUp, CheckCircle2 } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import Link from 'next/link';

export const metadata = {
  title: 'Meu Portfólio | Nipo School',
  description: 'Gerencie seus projetos e trabalhos acadêmicos',
};

// Mock data - substituir com dados reais do banco
const portfolios = [
  {
    id: '1',
    titulo: 'Recital de Piano - Primavera 2024',
    descricao: 'Preparação completa para apresentação de fim de semestre',
    status: 'em_andamento',
    progresso: 75,
    data_criacao: '2024-01-15',
    evidencias_count: 8,
  },
  {
    id: '2',
    titulo: 'Estudos de Teoria Musical',
    descricao: 'Compilação de exercícios e composições próprias',
    status: 'concluido',
    progresso: 100,
    data_criacao: '2023-11-20',
    evidencias_count: 15,
  },
  {
    id: '3',
    titulo: 'Prática de Violino Clássico',
    descricao: 'Técnicas e peças do repertório clássico',
    status: 'em_andamento',
    progresso: 45,
    data_criacao: '2024-02-01',
    evidencias_count: 5,
  },
];

const stats = {
  total: 3,
  em_andamento: 2,
  concluidos: 1,
  evidencias_total: 28,
};

function getStatusColor(status: string) {
  const colors = {
    em_andamento: 'bg-yellow-100 text-yellow-800 border-yellow-200',
    concluido: 'bg-green-100 text-green-800 border-green-200',
    arquivado: 'bg-gray-100 text-gray-800 border-gray-200',
    rascunho: 'bg-blue-100 text-blue-800 border-blue-200',
  };
  return colors[status as keyof typeof colors] || colors.rascunho;
}

function getStatusLabel(status: string) {
  const labels = {
    em_andamento: 'Em Andamento',
    concluido: 'Concluído',
    arquivado: 'Arquivado',
    rascunho: 'Rascunho',
  };
  return labels[status as keyof typeof labels] || status;
}

function PortfolioContent() {
  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
            <FolderOpen className="w-8 h-8 text-purple-600" />
            Meu Portfólio
          </h1>
          <p className="text-gray-600 mt-2">
            Gerencie seus projetos e trabalhos acadêmicos
          </p>
        </div>
        <Button asChild className="bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700">
          <Link href="/alunos/portfolio/novo">
            <Plus className="w-4 h-4 mr-2" />
            Novo Portfólio
          </Link>
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Total de Portfólios</p>
                <p className="text-2xl font-bold text-gray-900">{stats.total}</p>
              </div>
              <FolderOpen className="w-8 h-8 text-purple-600" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Em Andamento</p>
                <p className="text-2xl font-bold text-yellow-600">{stats.em_andamento}</p>
              </div>
              <TrendingUp className="w-8 h-8 text-yellow-600" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Concluídos</p>
                <p className="text-2xl font-bold text-green-600">{stats.concluidos}</p>
              </div>
              <CheckCircle2 className="w-8 h-8 text-green-600" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Total Evidências</p>
                <p className="text-2xl font-bold text-blue-600">{stats.evidencias_total}</p>
              </div>
              <FolderOpen className="w-8 h-8 text-blue-600" />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Portfolio List */}
      <div className="grid gap-4">
        {portfolios.map((portfolio) => (
          <Card key={portfolio.id} className="hover:shadow-lg transition-shadow">
            <CardHeader>
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <CardTitle className="text-xl mb-2">
                    <Link 
                      href={`/alunos/portfolio/${portfolio.id}`}
                      className="hover:text-purple-600 transition-colors"
                    >
                      {portfolio.titulo}
                    </Link>
                  </CardTitle>
                  <CardDescription>{portfolio.descricao}</CardDescription>
                </div>
                <Badge className={getStatusColor(portfolio.status)}>
                  {getStatusLabel(portfolio.status)}
                </Badge>
              </div>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {/* Progress Bar */}
                <div>
                  <div className="flex justify-between text-sm mb-2">
                    <span className="text-gray-600">Progresso</span>
                    <span className="font-medium">{portfolio.progresso}%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2">
                    <div
                      className="bg-gradient-to-r from-purple-600 to-pink-600 h-2 rounded-full transition-all duration-300"
                      style={{ width: `${portfolio.progresso}%` }}
                    />
                  </div>
                </div>

                {/* Metadata */}
                <div className="flex items-center justify-between text-sm text-gray-600">
                  <div className="flex items-center gap-4">
                    <span>📁 {portfolio.evidencias_count} evidências</span>
                    <span>📅 {new Date(portfolio.data_criacao).toLocaleDateString('pt-BR')}</span>
                  </div>
                  <Button asChild variant="outline" size="sm">
                    <Link href={`/alunos/portfolio/${portfolio.id}`}>
                      Ver Detalhes
                    </Link>
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Empty State */}
      {portfolios.length === 0 && (
        <Card className="p-12 text-center">
          <FolderOpen className="w-16 h-16 mx-auto mb-4 text-gray-400" />
          <h3 className="text-xl font-semibold text-gray-900 mb-2">
            Nenhum portfólio criado ainda
          </h3>
          <p className="text-gray-600 mb-6">
            Comece a documentar sua jornada musical criando seu primeiro portfólio
          </p>
          <Button asChild className="bg-gradient-to-r from-purple-600 to-pink-600">
            <Link href="/alunos/portfolio/novo">
              <Plus className="w-4 h-4 mr-2" />
              Criar Primeiro Portfólio
            </Link>
          </Button>
        </Card>
      )}
    </div>
  );
}

export default function PortfolioPage() {
  return (
    <Suspense fallback={<div className="p-8">Carregando portfólios...</div>}>
      <PortfolioContent />
    </Suspense>
  );
}
